INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0501', 'S1.1', 2, 'single_choice', 'Người bệnh xin xem hồ sơ bệnh án của mình. Ứng xử đúng của điều dưỡng:', '["Từ chối tuyệt đối", "Hướng dẫn theo quy định của cơ sở về quyền tiếp cận hồ sơ", "Đưa ngay bản gốc", "Xé bỏ phần nhạy cảm"]'::jsonb, 1, 'Người bệnh có quyền tiếp cận thông tin sức khỏe của mình theo quy trình cơ sở; ĐD hướng dẫn đúng thủ tục.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0502', 'S1.1', 1, 'single_choice', 'Nói sự thật về tình trạng bệnh cho người bệnh thể hiện nguyên tắc y đức nào?', '["Không làm hại", "Trung thực (veracity)", "Công bằng", "Bảo mật"]'::jsonb, 1, 'Trung thực là cung cấp thông tin đúng, không lừa dối, giúp NB đưa quyết định có hiểu biết.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0503', 'S1.1', 3, 'single_choice', 'Trong tình huống nguồn lực hạn chế phải ưu tiên NB, nguyên tắc đạo đức được áp dụng là:', '["Bảo mật", "Công bằng (justice) trong phân bổ nguồn lực", "Tự chủ", "Trung thực"]'::jsonb, 1, 'Phân bổ nguồn lực khan hiếm dựa trên nguyên tắc công bằng: theo nhu cầu/mức độ nặng, không thiên vị.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0504', 'S1.1', 2, 'single_choice', 'Giữ lời hứa với người bệnh (ví dụ quay lại đúng giờ đã hẹn) thuộc phẩm chất:', '["Vô cảm", "Đáng tin cậy và tôn trọng người bệnh", "Qua loa", "Cứng nhắc"]'::jsonb, 1, 'Giữ cam kết với NB xây dựng lòng tin và thể hiện sự tôn trọng — cốt lõi của quan hệ chăm sóc.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0505', 'S1.1', 2, 'single_choice', 'Khi chăm sóc NB khác tôn giáo/văn hóa với mình, ĐD nên:', '["Áp đặt quan điểm cá nhân", "Tôn trọng niềm tin, phong tục của NB trong giới hạn an toàn chuyên môn", "Bỏ mặc", "Chê bai"]'::jsonb, 1, 'Chăm sóc tôn trọng đa dạng văn hóa - tín ngưỡng, miễn không gây hại về mặt y khoa.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0506', 'S1.1', 1, 'single_choice', 'Bí mật thông tin người bệnh có thể được tiết lộ khi:', '["Bất kỳ ai hỏi", "Có yêu cầu hợp pháp hoặc vì lợi ích điều trị của NB", "Đồng nghiệp tò mò", "Đăng mạng xã hội"]'::jsonb, 1, 'Chỉ chia sẻ thông tin NB khi có cơ sở pháp lý/chuyên môn; cấm chia sẻ tùy tiện, nhất là lên mạng xã hội.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0507', 'S1.1', 3, 'single_choice', 'Điều dưỡng chứng kiến hành vi có thể gây hại NB nhưng do cấp trên chỉ đạo. Hành xử đúng:', '["Tuân theo tuyệt đối", "Nêu quan ngại, từ chối hành vi gây hại và báo cáo theo quy trình", "Im lặng làm theo", "Tự ý bỏ việc"]'::jsonb, 1, 'Nghĩa vụ bảo vệ NB cao hơn mệnh lệnh; ĐD phải lên tiếng, từ chối hành vi gây hại và báo cáo đúng kênh.', '', ARRAY['VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0508', 'S1.2', 2, 'single_choice', '"Đồng thuận có hiểu biết" chỉ có giá trị khi người bệnh:', '["Bị thúc ép ký", "Có năng lực, được thông tin đầy đủ và tự nguyện đồng ý", "Ký hộ bởi người khác", "Không đọc nội dung"]'::jsonb, 1, 'Consent hợp lệ đòi hỏi NB đủ năng lực, được cung cấp thông tin và quyết định tự nguyện, không bị ép buộc.', '', ARRAY['VB01','VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0509', 'S1.2', 1, 'single_choice', 'Điều dưỡng được phép thực hiện kỹ thuật mới khi:', '["Tự học qua video", "Đã được đào tạo, đánh giá năng lực và trong phạm vi cho phép", "Xem đồng nghiệp làm một lần", "Người bệnh yêu cầu"]'::jsonb, 1, 'Chỉ thực hiện kỹ thuật khi đã được huấn luyện, chứng minh năng lực và thuộc phạm vi hành nghề.', '', ARRAY['VB01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0510', 'S1.2', 2, 'single_choice', 'Trường hợp cấp cứu mà NB hôn mê không có người đại diện, việc xử trí dựa trên:', '["Chờ ký cam kết", "Nguyên tắc cứu chữa vì lợi ích tốt nhất cho NB", "Từ chối can thiệp", "Hỏi ý kiến mạng xã hội"]'::jsonb, 1, 'Trong cấp cứu đe dọa tính mạng khi không lấy được đồng thuận, ưu tiên can thiệp vì lợi ích tốt nhất của NB.', '', ARRAY['VB01','VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0511', 'S1.2', 1, 'single_choice', 'Ghi chép sai lệch hồ sơ để che giấu sự cố là hành vi:', '["Được chấp nhận", "Vi phạm đạo đức và pháp luật hành nghề", "Bình thường", "Khuyến khích"]'::jsonb, 1, 'Làm sai lệch hồ sơ là vi phạm nghiêm trọng tính trung thực và pháp lý; sự cố phải ghi nhận và báo cáo trung thực.', '', ARRAY['VB01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0512', 'S1.2', 2, 'single_choice', 'Phạm vi hành nghề của điều dưỡng được xác định chủ yếu bởi:', '["Ý muốn cá nhân", "Quy định pháp luật, văn bằng - chứng chỉ và năng lực đã được công nhận", "Thâm niên", "Cấp trên tùy ý"]'::jsonb, 1, 'Phạm vi hành nghề do quy định pháp luật và năng lực được công nhận quyết định, không tùy tiện mở rộng.', '', ARRAY['VB01','VB02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0513', 'S1.2', 3, 'single_choice', 'Ủy quyền/giao nhiệm vụ (delegation) cho ĐD/hộ lý cấp dưới an toàn khi:', '["Giao mọi việc bất kỳ", "Người nhận đủ năng lực, nhiệm vụ phù hợp phạm vi và có giám sát", "Không cần giám sát", "Giao cả việc ngoài chuyên môn"]'::jsonb, 1, 'Giao nhiệm vụ an toàn dựa trên năng lực người nhận, tính phù hợp của nhiệm vụ và sự giám sát thích hợp.', '', ARRAY['VB01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0514', 'S1.2', 2, 'single_choice', 'Khi không chắc chắn về một y lệnh thuốc liều cao bất thường, ĐD nên:', '["Cứ tiêm cho xong", "Tạm dừng, xác minh lại với người kê đơn trước khi thực hiện", "Giảm liều tùy ý", "Bỏ thuốc không báo"]'::jsonb, 1, 'Nghi ngờ y lệnh phải xác minh với người ra y lệnh; không tự ý thay đổi cũng không thực hiện mù quáng.', '', ARRAY['VB01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0515', 'S1.3', 2, 'single_choice', 'Nhiệt độ và độ ẩm trong buồng mổ được kiểm soát nhằm:', '["Tiết kiệm điện", "Hạn chế phát triển vi khuẩn và bảo đảm điều kiện vô khuẩn, thoải mái", "Làm mát nhân viên", "Không có mục đích"]'::jsonb, 1, 'Kiểm soát nhiệt độ - độ ẩm và thông khí buồng mổ giúp giảm nguy cơ nhiễm khuẩn và duy trì điều kiện phẫu thuật.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0516', 'S1.3', 1, 'single_choice', 'Hệ thống thông khí buồng mổ thường duy trì áp suất:', '["Âm so với hành lang", "Dương so với khu vực xung quanh", "Bằng nhau", "Không kiểm soát"]'::jsonb, 1, 'Buồng mổ duy trì áp suất dương để đẩy không khí ra ngoài, ngăn khí bẩn tràn vào khu vô khuẩn.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0517', 'S1.3', 2, 'single_choice', 'Số lượng người trong buồng mổ nên được hạn chế vì:', '["Tiết kiệm chỗ", "Càng nhiều người/di chuyển càng tăng phát tán vi khuẩn và nguy cơ nhiễm", "Cho yên tĩnh", "Giảm chi phí"]'::jsonb, 1, 'Đông người và đi lại nhiều làm tăng phát tán vi sinh vật trong không khí buồng mổ, tăng nguy cơ nhiễm khuẩn vết mổ.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0518', 'S1.3', 3, 'single_choice', 'Phân công vai trò rõ ràng trong kíp mổ (PTV, gây mê, dụng cụ, vòng ngoài) nhằm:', '["Hình thức", "Bảo đảm phối hợp an toàn, không chồng chéo/bỏ sót nhiệm vụ", "Tăng nhân sự", "Phân cấp lương"]'::jsonb, 1, 'Vai trò rõ ràng trong kíp mổ giúp phối hợp trơn tru, tránh bỏ sót các bước an toàn quan trọng.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0519', 'S1.3', 1, 'single_choice', 'Trang phục phòng mổ (scrub) không được mặc ra ngoài khu phẫu thuật vì:', '["Xấu", "Tránh mang vi khuẩn từ bên ngoài vào và ngược lại", "Quy định thời trang", "Giữ ấm"]'::jsonb, 1, 'Trang phục phòng mổ chỉ dùng trong khu phẫu thuật để tránh lây nhiễm chéo giữa trong và ngoài.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0520', 'S1.3', 2, 'single_choice', 'Lưu trữ hồ sơ khoa PTGMHS (biên bản mổ, phiếu gây mê) nhằm:', '["Cho đầy tủ", "Bằng chứng chuyên môn - pháp lý và phục vụ tra cứu, nghiên cứu", "Trang trí", "Không cần thiết"]'::jsonb, 1, 'Hồ sơ phẫu thuật - gây mê là tài liệu pháp lý và chuyên môn, phải lưu trữ đầy đủ theo quy định.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0521', 'S1.3', 2, 'single_choice', 'Khi xảy ra sự cố trong mổ, quy chế khoa yêu cầu:', '["Giấu kín", "Ghi nhận, xử trí kịp thời và báo cáo theo quy trình", "Đổ lỗi cho NB", "Bỏ qua"]'::jsonb, 1, 'Sự cố phải được xử trí ngay, ghi nhận trung thực và báo cáo theo quy trình an toàn người bệnh của cơ sở.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0522', 'S2.1', 2, 'single_choice', 'Người bệnh dùng thuốc chống đông (warfarin) chuẩn bị mổ chương trình cần:', '["Giữ nguyên liều", "Đánh giá và điều chỉnh theo phác đồ, cân nhắc ngưng/bắc cầu theo chỉ định", "Tăng liều", "Bỏ hẳn không hỏi"]'::jsonb, 1, 'Thuốc chống đông làm tăng nguy cơ chảy máu; cần đánh giá và xử trí chu phẫu theo chỉ định bác sĩ (ngưng/bắc cầu).', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0523', 'S2.1', 1, 'single_choice', 'Trước mổ cần đánh giá dấu hiệu sinh tồn nền để:', '["Cho đủ thủ tục", "Có mốc so sánh và phát hiện bất thường cần xử trí trước gây mê", "Tính tiền", "Chọn phòng"]'::jsonb, 1, 'Dấu hiệu sinh tồn nền là mốc tham chiếu và giúp phát hiện bất thường (sốt, tăng HA...) cần xử lý trước mổ.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0524', 'S2.1', 2, 'single_choice', 'Với NB tăng huyết áp chưa kiểm soát đến mổ chương trình, thường:', '["Mổ ngay bất kể", "Cân nhắc hoãn để ổn định huyết áp trước, theo hội chẩn", "Cho về hẳn", "Tăng liều mê"]'::jsonb, 1, 'THA chưa kiểm soát làm tăng nguy cơ biến cố tim mạch chu phẫu; mổ chương trình thường hoãn để ổn định trước.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0525', 'S2.1', 1, 'single_choice', 'Giáo dục trước mổ cho NB nên bao gồm:', '["Chỉ giờ mổ", "Quy trình, nhịn ăn, đau sau mổ, tập thở/ho và vận động sớm", "Chỉ chi phí", "Không cần"]'::jsonb, 1, 'Chuẩn bị tâm lý và hướng dẫn trước mổ (nhịn ăn, kiểm soát đau, tập thở, vận động) giúp giảm lo âu và biến chứng.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0526', 'S2.1', 2, 'single_choice', 'Đánh giá nguy cơ té ngã và loét tì đè trước mổ quan trọng với đối tượng:', '["Trẻ khỏe", "Người cao tuổi, hạn chế vận động, suy kiệt", "Mọi người như nhau", "Không ai"]'::jsonb, 1, 'NB cao tuổi/suy kiệt/giảm vận động có nguy cơ cao té ngã và loét tì đè, cần đánh giá và dự phòng sớm.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0527', 'S2.1', 3, 'single_choice', 'NB nghi ngờ "dạ dày đầy" (ăn gần đây, cấp cứu) cần lưu ý khi gây mê vì:', '["Không sao", "Nguy cơ trào ngược - hít sặc cao, cân nhắc khởi mê nhanh (RSI)", "Mê nhanh hơn", "Ít đau hơn"]'::jsonb, 1, 'Dạ dày đầy làm tăng nguy cơ hít sặc; thường áp dụng khởi mê nhanh có ấn sụn nhẫn để giảm rủi ro.', '', ARRAY['CS01','KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0528', 'S2.1', 1, 'single_choice', 'Kiểm tra kết quả cận lâm sàng cần thiết trước mổ nhằm:', '["Cho đủ giấy", "Phát hiện bất thường (thiếu máu, rối loạn đông máu, điện giải) cần xử lý", "Tính điểm", "Không mục đích"]'::jsonb, 1, 'Xét nghiệm trước mổ phù hợp giúp phát hiện và xử lý bất thường trước khi gây mê - phẫu thuật.', '', ARRAY['CS01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0529', 'S2.1', 2, 'single_choice', 'Dự phòng huyết khối tĩnh mạch (VTE) chu phẫu có thể gồm:', '["Bất động lâu", "Vận động sớm, tất áp lực và/hoặc thuốc chống đông theo nguy cơ", "Nằm bất động tuyệt đối", "Không cần"]'::jsonb, 1, 'Dự phòng VTE gồm vận động sớm, phương tiện cơ học (tất/bơm hơi) và thuốc chống đông tùy mức nguy cơ.', '', ARRAY['CS01','CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0530', 'S2.2', 2, 'single_choice', 'Chăm sóc vết mổ trong 24-48 giờ đầu thường:', '["Mở băng liên tục", "Giữ băng vô khuẩn, theo dõi thấm dịch/chảy máu, hạn chế can thiệp không cần thiết", "Rửa xà phòng mạnh", "Bóc vảy sớm"]'::jsonb, 1, '48 giờ đầu giữ băng vô khuẩn, theo dõi dấu hiệu chảy máu/nhiễm; tránh mở băng không cần thiết.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0531', 'S2.2', 1, 'single_choice', 'Dấu hiệu nhiễm khuẩn vết mổ gồm:', '["Da bình thường", "Sưng, nóng, đỏ, đau tăng, chảy dịch đục/mủ, có thể sốt", "Vết khô sạch", "Hết đau nhanh"]'::jsonb, 1, 'Nhiễm khuẩn vết mổ biểu hiện sưng - nóng - đỏ - đau, chảy dịch mủ, đôi khi kèm sốt; cần báo và xử trí.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0532', 'S2.2', 2, 'single_choice', 'Kiểm soát đau sau mổ hiệu quả nên theo hướng:', '["Chỉ dùng khi đau dữ dội", "Đa mô thức (multimodal) và đánh giá đau định kỳ bằng thang điểm", "Chỉ một loại opioid liều cao", "Không dùng thuốc"]'::jsonb, 1, 'Giảm đau đa mô thức phối hợp nhiều nhóm thuốc, kèm đánh giá đau định kỳ, giảm liều opioid và tác dụng phụ.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0533', 'S2.2', 1, 'single_choice', 'Thang điểm đánh giá đau thường dùng ở người lớn tỉnh táo là:', '["Glasgow", "VAS/NRS (0-10)", "Aldrete", "ASA"]'::jsonb, 1, 'Thang VAS/NRS (0-10) để NB tự đánh giá cường độ đau, hướng dẫn điều chỉnh giảm đau.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0534', 'S2.2', 3, 'single_choice', 'NB sau mổ bụng ngày 2 chướng bụng, không trung tiện, đau tăng — nghĩ đến:', '["Bình thường", "Liệt ruột hoặc biến chứng ổ bụng, cần đánh giá và báo bác sĩ", "Đói", "Lo âu"]'::jsonb, 1, 'Chướng bụng, bí trung tiện, đau tăng gợi ý liệt ruột kéo dài hoặc biến chứng (tắc, viêm phúc mạc); cần đánh giá.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0535', 'S2.2', 2, 'single_choice', 'Tập thở sâu và ho có kiểm soát sau mổ nhằm:', '["Giảm cân", "Phòng xẹp phổi và viêm phổi ứ đọng", "Tăng đau", "Giảm nhịp tim"]'::jsonb, 1, 'Bài tập thở sâu, ho hỗ trợ giãn nở phổi, tống đàm, phòng xẹp phổi và viêm phổi sau mổ.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0536', 'S2.2', 1, 'single_choice', 'Theo dõi cân bằng dịch vào - ra sau mổ giúp:', '["Không ý nghĩa", "Phát hiện thiếu/thừa dịch và điều chỉnh kịp thời", "Tính tiền", "Giảm đau"]'::jsonb, 1, 'Ghi dịch vào - ra (truyền, uống, nước tiểu, dẫn lưu) giúp đánh giá và điều chỉnh cân bằng dịch sau mổ.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0537', 'S2.2', 2, 'single_choice', 'Chăm sóc ống dẫn lưu sau mổ cần:', '["Kẹp kín liên tục", "Giữ thông, cố định, theo dõi dịch và vô khuẩn khi thao tác", "Kéo mạnh mỗi ngày", "Mở đầu ống ra khí trời"]'::jsonb, 1, 'Ống dẫn lưu cần giữ thông, cố định chắc, theo dõi tính chất/số lượng dịch và thao tác vô khuẩn để tránh nhiễm.', '', ARRAY['CS03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0538', 'S2.3', 2, 'single_choice', 'NB tại hồi tỉnh kích thích, giãy giụa, cần loại trừ đầu tiên nguyên nhân:', '["Tính cách", "Thiếu oxy máu", "Buồn ngủ", "Đói"]'::jsonb, 1, 'Kích thích/lú lẫn sau mổ phải loại trừ thiếu oxy trước tiên trước khi quy cho đau hay nguyên nhân khác.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0539', 'S2.3', 1, 'single_choice', 'Đánh giá đau ở NB hồi tỉnh chưa tỉnh hẳn có thể dựa vào:', '["Không cần", "Dấu hiệu hành vi (nhăn mặt, rên) và sinh tồn kết hợp thang điểm phù hợp", "Cân nặng", "Nhóm máu"]'::jsonb, 1, 'Với NB chưa giao tiếp tốt, đánh giá đau qua biểu hiện hành vi và dấu hiệu sinh tồn, dùng thang phù hợp.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0540', 'S2.3', 3, 'single_choice', 'NB hồi tỉnh SpO2 tụt dù thở oxy, nghe phổi ran ẩm, khó thở tăng — nghĩ nhiều đến:', '["Táo bón", "Phù phổi/quá tải dịch hoặc biến chứng hô hấp, cần báo xử trí ngay", "Đói", "Lo âu"]'::jsonb, 1, 'SpO2 tụt kèm ran ẩm và khó thở gợi ý phù phổi/quá tải hoặc biến chứng phổi; cần đánh giá và xử trí khẩn.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0541', 'S2.3', 2, 'single_choice', 'Theo dõi chảy máu sau mổ tại hồi tỉnh gồm:', '["Chỉ hỏi NB", "Băng vết mổ, dẫn lưu, mạch - huyết áp và dấu hiệu sốc", "Chỉ nhiệt độ", "Cân nặng"]'::jsonb, 1, 'Phát hiện chảy máu dựa trên thấm băng, dịch dẫn lưu, mạch nhanh - HA tụt và dấu hiệu giảm tưới máu.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0542', 'S2.3', 1, 'single_choice', 'Ủ ấm cho NB hồi tỉnh bị hạ thân nhiệt giúp:', '["Tăng chảy máu", "Giảm run, giảm tiêu thụ oxy và cải thiện tuần hoàn", "Hạ huyết áp", "Kéo dài mê"]'::jsonb, 1, 'Ủ ấm khắc phục hạ thân nhiệt, giảm run và nhu cầu oxy, hỗ trợ đông máu và huyết động.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0543', 'S2.3', 2, 'single_choice', 'Tiêu chí Aldrete đánh giá gồm các thành phần:', '["Chỉ SpO2", "Vận động, hô hấp, tuần hoàn, tri giác và độ bão hòa oxy", "Cân nặng, chiều cao", "Nhóm máu, Rh"]'::jsonb, 1, 'Thang Aldrete gồm 5 yếu tố: vận động, hô hấp, tuần hoàn (HA), tri giác, SpO2 — mỗi mục 0-2 điểm.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0544', 'S2.3', 3, 'single_choice', 'NB sau gây tê tủy sống than tê lan cao, khó thở, HA tụt nhanh — nghĩ đến:', '["Bình thường", "Tê tủy sống lan cao (high spinal) ảnh hưởng hô hấp/tuần hoàn, cần cấp cứu", "Đói", "Lo âu"]'::jsonb, 1, 'Tê lan cao có thể liệt cơ hô hấp và tụt HA nặng; cần hỗ trợ hô hấp, bù dịch, thuốc co mạch và gọi hỗ trợ ngay.', '+', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0545', 'S2.4', 2, 'single_choice', 'Thông số PEEP trên máy thở có tác dụng chính:', '["Giảm oxy", "Giữ phế nang mở cuối thì thở ra, cải thiện oxy hóa", "Tăng CO2", "Giảm nhịp thở"]'::jsonb, 1, 'PEEP duy trì áp lực dương cuối thì thở ra giúp mở phế nang, cải thiện trao đổi oxy và phòng xẹp phổi.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0546', 'S2.4', 1, 'single_choice', 'Ẩm hóa khí thở cho NB thở máy nhằm:', '["Làm mát", "Giữ ẩm đường thở, tránh khô và đàm đặc gây tắc ống", "Giảm oxy", "Tăng áp lực"]'::jsonb, 1, 'Làm ẩm khí thở tránh khô niêm mạc và đàm đặc, giảm nguy cơ tắc nghẽn ống nội khí quản.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0547', 'S2.4', 2, 'single_choice', 'Đánh giá NB thở máy đột ngột tụt SpO2 nên theo tiếp cận (ví dụ DOPE), loại trừ:', '["Đói", "Tuột/tắc ống, tràn khí màng phổi, trục trặc máy", "Táo bón", "Lo âu"]'::jsonb, 1, 'Tụt SpO2 cấp ở NB thở máy: kiểm tra Displacement (tuột ống), Obstruction (tắc), Pneumothorax, Equipment.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0548', 'S2.4', 1, 'single_choice', 'Cố định ống nội khí quản chắc chắn nhằm:', '["Thẩm mỹ", "Tránh tuột ống hoặc di lệch sâu một bên", "Giảm đau", "Tăng oxy"]'::jsonb, 1, 'Cố định ống tốt ngăn tuột ra ngoài (mất đường thở) hoặc tụt sâu vào một phế quản.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0549', 'S2.4', 3, 'single_choice', 'Chăm sóc mắt cho NB an thần/thở máy nhằm phòng:', '["Tăng nhãn áp", "Khô giác mạc và loét giác mạc do mất phản xạ chớp mắt", "Đau đầu", "Sốt"]'::jsonb, 1, 'NB an thần mất phản xạ chớp và nhắm mắt không kín, dễ khô - loét giác mạc; cần nhỏ ẩm và che chở mắt.', '*', ARRAY['CS04'], 'approved') ON CONFLICT (id) DO NOTHING;
