INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0552', 'S3.1', 1, 'single_choice', 'Người nhóm máu A có kháng thể nào trong huyết thanh?', '["Kháng A", "Kháng B", "Cả kháng A và B", "Không có"]'::jsonb, 1, 'Nhóm A có kháng nguyên A trên hồng cầu và kháng thể kháng B trong huyết thanh.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
