INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0556', 'S3.1', 2, 'single_choice', 'Trước khi lấy máu định nhóm và làm phản ứng chéo, cần đặc biệt chú ý:', '["Lấy nhanh cho xong", "Định danh đúng NB và dán nhãn ống ngay tại giường", "Không cần nhãn", "Ghi sau"]'::jsonb, 1, 'Sai sót định danh khi lấy mẫu là nguyên nhân chính gây truyền nhầm; phải xác nhận NB và dán nhãn tại giường.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0557', 'S3.1', 1, 'single_choice', 'Kết quả định nhóm: hồng cầu ngưng kết với cả anti-A và anti-B. NB thuộc nhóm:', '["O", "AB", "A", "B"]'::jsonb, 1, 'Ngưng kết với cả anti-A và anti-B nghĩa là hồng cầu mang cả kháng nguyên A và B — nhóm AB.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0558', 'S3.1', 2, 'single_choice', 'Kỹ thuật định nhóm trên phiến/giấy cần đọc kết quả:', '["Sau vài giờ", "Trong thời gian quy định, tránh để khô làm dương tính giả", "Bất kỳ lúc nào", "Chỉ khi có ngưng kết mạnh"]'::jsonb, 1, 'Đọc ngưng kết đúng thời gian quy định; để quá lâu/khô gây kết tụ giả, dễ đọc sai nhóm.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0559', 'S3.1', 3, 'single_choice', 'Khi định nhóm gặp ngưng kết yếu/không rõ, xử trí đúng là:', '["Kết luận đại", "Làm lại, dùng kỹ thuật xác định thêm, không truyền tới khi rõ nhóm", "Chọn nhóm O", "Bỏ qua"]'::jsonb, 1, 'Ngưng kết mơ hồ có thể do nhiều nguyên nhân; phải làm lại/định nhóm bổ sung và không truyền cho tới khi chắc chắn.', '*', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0560', 'S3.2', 2, 'single_choice', 'Khối hồng cầu được bảo quản ở nhiệt độ:', '["20-24 C", "2-6 C", "-18 C", "37 C"]'::jsonb, 1, 'Hồng cầu lắng bảo quản ở 2-6 C trong tủ lạnh chuyên dụng có kiểm soát nhiệt độ.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0561', 'S3.2', 1, 'single_choice', 'Huyết tương tươi đông lạnh (FFP) bảo quản ở:', '["2-6 C", "Đông lạnh (≤ -18 C hoặc thấp hơn)", "Nhiệt độ phòng", "37 C liên tục"]'::jsonb, 1, 'FFP được giữ đông lạnh (thường ≤ -18 C) để bảo tồn yếu tố đông máu, rã đông trước khi truyền.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0562', 'S3.2', 2, 'single_choice', 'FFP sau khi rã đông cần:', '["Để lại đông", "Truyền trong thời gian quy định, không đông lại", "Đun nóng", "Trộn hồng cầu"]'::jsonb, 1, 'FFP đã rã đông phải dùng trong khoảng thời gian quy định và không được cấp đông lại để bảo đảm chất lượng.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0563', 'S3.2', 1, 'single_choice', 'Chỉ định truyền khối tiểu cầu điển hình là:', '["Thiếu máu", "Giảm tiểu cầu nặng có nguy cơ/đang chảy máu", "Thiếu yếu tố đông", "Tăng đông"]'::jsonb, 1, 'Khối tiểu cầu dùng khi số lượng/chức năng tiểu cầu thấp gây hoặc đe dọa chảy máu.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0564', 'S3.2', 3, 'single_choice', 'Tủa lạnh được ưu tiên dùng khi:', '["Thiếu máu", "Giảm fibrinogen máu (ví dụ trong đông máu rải rác nội mạch)", "Giảm tiểu cầu", "Tăng kali"]'::jsonb, 1, 'Tủa lạnh giàu fibrinogen, chỉ định khi giảm fibrinogen (DIC, chảy máu sản khoa...) cần bổ sung nhanh.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0565', 'S3.2', 2, 'single_choice', 'Nguyên tắc khi vận chuyển chế phẩm máu từ ngân hàng máu về khoa:', '["Để nhiệt độ phòng lâu", "Giữ dây chuyền lạnh đúng và truyền sớm sau khi nhận", "Đun ấm bằng lò vi sóng", "Lắc mạnh"]'::jsonb, 1, 'Duy trì dây chuyền lạnh/điều kiện bảo quản khi vận chuyển và truyền sớm; cấm hâm bằng lò vi sóng.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0566', 'S3.2', 1, 'single_choice', 'Chế phẩm máu trước khi truyền phải được kiểm tra:', '["Chỉ hạn dùng", "Hạn dùng, tính toàn vẹn túi, màu sắc bất thường và thông tin nhãn", "Chỉ màu sắc", "Không cần"]'::jsonb, 1, 'Trước truyền kiểm tra hạn dùng, túi có rò/vón/đổi màu bất thường và đối chiếu thông tin nhãn với NB.', '', ARRAY['KT01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0567', 'S3.3', 1, 'single_choice', 'Tốc độ truyền máu trong khoảng 15 phút đầu nên:', '["Nhanh tối đa", "Chậm và theo dõi sát để phát hiện phản ứng sớm", "Ngắt quãng", "Không quan trọng"]'::jsonb, 1, 'Truyền chậm 15 phút đầu và theo dõi sát vì phản ứng nặng thường xuất hiện sớm.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0568', 'S3.3', 2, 'single_choice', 'Một đơn vị máu nên được truyền xong trong thời gian tối đa khoảng:', '["30 phút", "4 giờ", "12 giờ", "24 giờ"]'::jsonb, 1, 'Một đơn vị máu nên truyền trong vòng 4 giờ để hạn chế nguy cơ nhiễm khuẩn khi để ngoài dây chuyền lạnh.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0569', 'S3.3', 3, 'single_choice', 'Dấu hiệu KHÔNG điển hình của phản ứng tan máu cấp là:', '["Sốt, rét run", "Đau lưng/đau ngực", "Nước tiểu sẫm màu", "Hết đau, dễ chịu hẳn"]'::jsonb, 3, 'Tan máu cấp gây sốt, rét run, đau lưng/ngực, tiểu sẫm, tụt HA — không phải cảm giác dễ chịu.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0570', 'S3.3', 1, 'single_choice', 'Khi ngừng truyền do phản ứng, đường truyền được giữ bằng:', '["Glucose 5%", "NaCl 0,9%", "Ringer có calci", "Nước cất"]'::jsonb, 1, 'Giữ ven bằng NaCl 0,9% sau khi ngừng máu để duy trì đường truyền và không gây tan/đông trong dây.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0571', 'S3.3', 2, 'single_choice', 'Sưởi ấm máu (blood warmer) được cân nhắc khi:', '["Mọi lần truyền", "Truyền khối lượng lớn/nhanh hoặc NB nguy cơ hạ thân nhiệt", "Truyền chậm 1 đơn vị", "Không bao giờ"]'::jsonb, 1, 'Làm ấm máu bằng thiết bị chuyên dụng chỉ định khi truyền nhanh/khối lượng lớn hoặc NB dễ hạ thân nhiệt.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0572', 'S3.3', 3, 'single_choice', 'Truyền máu khối lượng lớn có thể gây rối loạn:', '["Không gì", "Hạ calci, hạ thân nhiệt, rối loạn đông máu và tăng kali", "Tăng cân", "Táo bón"]'::jsonb, 1, 'Truyền máu lượng lớn có thể gây hạ calci (do citrate), hạ thân nhiệt, rối loạn đông và tăng kali máu.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0573', 'S3.3', 1, 'single_choice', 'Hồ sơ truyền máu cần ghi lại:', '["Chỉ tên NB", "Loại - số lượng chế phẩm, thời gian, dấu hiệu sinh tồn và phản ứng (nếu có)", "Chỉ giờ bắt đầu", "Không cần ghi"]'::jsonb, 1, 'Ghi đầy đủ chế phẩm, thời gian, theo dõi sinh tồn và diễn biến/phản ứng để bảo đảm an toàn và truy xuất.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0574', 'S3.4', 2, 'single_choice', 'Trước rút nội khí quản, đánh giá "rò khí quanh cuff" (cuff leak) nhằm:', '["Đo huyết áp", "Dự đoán nguy cơ phù nề thanh môn gây tắc sau rút", "Giảm đau", "Tăng oxy"]'::jsonb, 1, 'Nghiệm pháp rò cuff giúp tiên lượng phù nề thanh môn; thiếu rò khí cảnh báo nguy cơ tắc nghẽn sau rút.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0575', 'S3.4', 1, 'single_choice', 'Sau rút ống, để giảm phù nề đường thở có thể:', '["Cho ăn ngay", "Cho thở oxy ẩm, theo dõi, dùng thuốc theo y lệnh nếu cần", "Cho vận động mạnh", "Nằm đầu thấp"]'::jsonb, 1, 'Oxy ẩm và theo dõi sát sau rút; corticoid/khí dung theo y lệnh nếu có nguy cơ phù nề.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0576', 'S3.4', 2, 'single_choice', 'Chuẩn bị sẵn dụng cụ đặt lại nội khí quản trước khi rút vì:', '["Thừa", "Đề phòng rút thất bại phải đặt lại cấp cứu", "Trang trí", "Quy định giấy tờ"]'::jsonb, 1, 'Luôn sẵn sàng dụng cụ đặt lại NKQ và hồi sức vì rút ống có thể thất bại và cần can thiệp ngay.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0577', 'S3.4', 1, 'single_choice', 'Sau rút ống, NB được khuyến khích:', '["Nằm im tuyệt đối", "Thở sâu, ho khạc đàm và theo dõi kiểu thở", "Ăn no ngay", "Vận động gắng sức"]'::jsonb, 1, 'Khuyến khích thở sâu và ho khạc giúp thông thoáng đường thở; theo dõi kiểu thở phát hiện suy hô hấp.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0578', 'S3.4', 3, 'single_choice', 'Thở rít (stridor) xuất hiện sau rút ống là dấu hiệu của:', '["Bình thường", "Hẹp/phù nề đường thở trên, cần xử trí ngay", "Đói", "Táo bón"]'::jsonb, 1, 'Stridor sau rút gợi ý tắc nghẽn/phù nề đường thở trên; cần oxy, khí dung adrenaline/corticoid theo y lệnh và sẵn sàng đặt lại.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0579', 'S3.4', 2, 'single_choice', 'Thời điểm rút ống lý tưởng liên quan giãn cơ tồn dư là khi:', '["Còn giãn cơ", "Giãn cơ đã hồi phục đủ (đánh giá TOF nếu có)", "Không cần quan tâm", "Càng sớm càng tốt bất kể"]'::jsonb, 1, 'Rút ống an toàn khi tác dụng giãn cơ đã hồi phục đủ (ví dụ TOF đạt), tránh yếu cơ hô hấp sau rút.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0580', 'S3.4', 1, 'single_choice', 'Hút đàm trước rút ống nên dùng kỹ thuật:', '["Sạch thường", "Vô khuẩn", "Không cần găng", "Tùy tiện"]'::jsonb, 1, 'Hút đàm nội khí quản là thủ thuật vô khuẩn để tránh đưa vi khuẩn vào đường thở dưới.', '', ARRAY['KT03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0581', 'S3.5', 1, 'single_choice', '"Time out" trước rạch da có sự tham gia của:', '["Chỉ PTV", "Toàn kíp mổ (PTV, gây mê, điều dưỡng)", "Chỉ điều dưỡng", "Người nhà"]'::jsonb, 1, 'Time out là khoảng dừng có sự tham gia của cả kíp để cùng xác nhận thông tin an toàn trước khi rạch da.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0582', 'S3.5', 2, 'single_choice', 'Khi chuyển dụng cụ sắc nhọn giữa PTV và ĐD dụng cụ, nên dùng:', '["Chuyền tay trực tiếp nhanh", "Khay/vùng trung gian (no-touch/neutral zone) để tránh tổn thương", "Ném qua", "Tay không"]'::jsonb, 1, 'Dùng vùng trung gian (neutral zone) khi chuyển vật sắc nhọn giảm nguy cơ tổn thương do kim/dao đâm.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0583', 'S3.5', 1, 'single_choice', 'Áo và găng vô khuẩn của ĐD dụng cụ được mang theo kỹ thuật:', '["Chạm mặt ngoài thoải mái", "Kỹ thuật vô khuẩn (không chạm mặt ngoài áo/găng bằng tay trần)", "Bất kỳ", "Nhờ NB"]'::jsonb, 1, 'Mang áo - găng theo kỹ thuật vô khuẩn, không để tay trần chạm mặt ngoài vô khuẩn.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0584', 'S3.5', 2, 'single_choice', 'Khăn trải vô khuẩn tạo vùng mổ, khi đã đặt thì:', '["Di chuyển tùy ý", "Không kéo dịch chuyển (chỉ được di từ vùng sạch ra, không kéo ngược)", "Kéo qua kéo lại", "Lật lên lật xuống"]'::jsonb, 1, 'Khăn vô khuẩn khi đã đặt không được kéo ngược về; kéo dịch chuyển làm vùng không vô khuẩn tràn vào vùng mổ.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0585', 'S3.5', 3, 'single_choice', 'Trong mổ, ĐD dụng cụ phát hiện thiếu 1 gạc khi đếm cuối. Xử trí:', '["Đóng bụng luôn", "Báo kíp, tìm kiếm và không đóng khoang cho tới khi khớp số hoặc loại trừ (chụp X-quang nếu cần)", "Ghi chú rồi thôi", "Đổ lỗi"]'::jsonb, 1, 'Đếm không khớp phải báo kíp, tìm gạc, giữ chưa đóng khoang; nếu không tìm thấy cân nhắc chụp X-quang loại trừ sót.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0586', 'S3.5', 1, 'single_choice', 'Giữ tay ở tư thế nào sau khi đã mang găng vô khuẩn chờ mổ?', '["Buông thõng", "Khoanh trước ngực, trên thắt lưng trong vùng vô khuẩn", "Chống hông", "Để sau lưng"]'::jsonb, 1, 'Sau khi vô khuẩn, giữ tay trên thắt lưng, trong tầm vùng vô khuẩn (thường khoanh trước ngực) tránh nhiễm.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0587', 'S3.5', 2, 'single_choice', 'Nếu găng vô khuẩn bị thủng trong mổ, xử trí:', '["Kệ nó", "Thay găng ngay theo kỹ thuật vô khuẩn", "Dán băng keo", "Rửa cồn"]'::jsonb, 1, 'Găng thủng làm mất hàng rào vô khuẩn và bảo hộ; phải thay găng mới ngay đúng kỹ thuật.', '', ARRAY['KT04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0588', 'S3.6', 2, 'single_choice', 'Ba phương pháp tiệt khuẩn dụng cụ phổ biến gồm:', '["Chỉ lau cồn", "Hơi nước áp lực (autoclave), nhiệt độ thấp (EO/plasma), hóa chất", "Chỉ ngâm nước", "Phơi nắng"]'::jsonb, 1, 'Tiệt khuẩn gồm hơi nước áp lực (hấp ướt), nhiệt độ thấp (ethylene oxide/plasma) và hóa chất — tùy loại dụng cụ.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0589', 'S3.6', 1, 'single_choice', 'Dụng cụ chịu nhiệt, chịu ẩm thường được tiệt khuẩn bằng:', '["EO", "Autoclave (hơi nước áp lực)", "Phơi nắng", "Cồn"]'::jsonb, 1, 'Hấp ướt (autoclave) là phương pháp ưu tiên cho dụng cụ kim loại chịu nhiệt - ẩm vì hiệu quả và an toàn.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0590', 'S3.6', 3, 'single_choice', 'Chỉ thị sinh học (biological indicator) dùng để:', '["Đo nhiệt độ phòng", "Xác nhận hiệu quả tiệt khuẩn bằng bào tử vi khuẩn thử thách", "Đếm dụng cụ", "Ghi hạn dùng"]'::jsonb, 1, 'Chỉ thị sinh học chứa bào tử kháng nhiệt, kiểm chứng chu trình tiệt khuẩn thực sự tiêu diệt được vi sinh vật.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0591', 'S3.6', 2, 'single_choice', 'Làm sạch dụng cụ (cleaning) trước tiệt khuẩn là bước:', '["Không cần", "Bắt buộc, vì chất bẩn hữu cơ cản trở tiệt khuẩn", "Tùy chọn", "Sau tiệt khuẩn"]'::jsonb, 1, 'Máu, mô bám làm giảm hiệu quả tiệt khuẩn; làm sạch kỹ là bước bắt buộc trước khi tiệt khuẩn.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0592', 'S3.6', 1, 'single_choice', 'Gói dụng cụ tiệt khuẩn được lưu trữ nơi:', '["Ẩm, gần bồn rửa", "Khô, sạch, kín, tránh ẩm và bụi", "Ngoài trời", "Cạnh rác"]'::jsonb, 1, 'Bảo quản gói tiệt khuẩn nơi khô sạch, tránh ẩm bụi để duy trì tính vô khuẩn cho tới khi dùng.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0593', 'S3.6', 2, 'single_choice', 'Chuẩn bị dụng cụ cho ca mổ tiếp theo cần đối chiếu:', '["Không cần", "Bộ dụng cụ theo loại phẫu thuật và kiểm tra đủ, còn tốt", "Bất kỳ bộ nào", "Chỉ số lượng"]'::jsonb, 1, 'Chuẩn bị đúng bộ dụng cụ theo loại phẫu thuật, kiểm đủ số lượng và tình trạng dụng cụ trước ca mổ.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0594', 'S3.6', 1, 'single_choice', 'Dụng cụ nội soi (ống soi mềm) thường xử lý bằng:', '["Hấp ướt nhiệt cao", "Khử khuẩn mức độ cao/tiệt khuẩn nhiệt độ thấp vì nhạy nhiệt", "Phơi nắng", "Cồn lau ngoài"]'::jsonb, 1, 'Ống soi nhạy nhiệt không hấp ướt được; xử lý bằng khử khuẩn mức cao hoặc tiệt khuẩn nhiệt độ thấp.', '', ARRAY['KT05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0595', 'S3.7', 2, 'single_choice', 'Kích cỡ thông tiểu (Foley) nên chọn:', '["Càng to càng tốt", "Nhỏ nhất đủ dẫn lưu tốt để giảm tổn thương niệu đạo", "Cố định 1 cỡ", "Ngẫu nhiên"]'::jsonb, 1, 'Chọn cỡ thông nhỏ nhất bảo đảm dẫn lưu tốt để hạn chế tổn thương và kích ứng niệu đạo.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0596', 'S3.7', 1, 'single_choice', 'Dung dịch bơm bóng chèn thông Foley thường là:', '["Không khí", "Nước cất vô khuẩn", "Nước muối ưu trương", "Cồn"]'::jsonb, 1, 'Bóng chèn được bơm bằng nước cất/nước vô khuẩn đúng thể tích ghi trên thông; không dùng khí (dễ xẹp).', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0597', 'S3.7', 3, 'single_choice', 'NB nam đặt thông tiểu bị đau chói và không ra nước tiểu, nghi ngờ:', '["Bình thường", "Đầu thông chưa vào bàng quang/ tổn thương niệu đạo — ngừng, không bơm bóng", "Uống ít nước", "Táo bón"]'::jsonb, 1, 'Đau chói, không có nước tiểu cảnh báo thông chưa vào bàng quang hoặc tạo đường giả; dừng lại, không bơm bóng, đánh giá lại.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0598', 'S3.7', 2, 'single_choice', 'Để phòng nhiễm khuẩn, hệ thống dẫn lưu nước tiểu nên là:', '["Hệ hở", "Hệ kín (closed drainage), hạn chế tháo rời", "Thay liên tục", "Mở túi thường xuyên"]'::jsonb, 1, 'Duy trì hệ thống dẫn lưu kín, hạn chế tháo rời giúp giảm nhiễm khuẩn tiết niệu liên quan thông tiểu.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0599', 'S3.7', 1, 'single_choice', 'Khi tháo bỏ thông tiểu, trước tiên cần:', '["Kéo mạnh", "Xả hết dịch trong bóng chèn rồi mới rút nhẹ", "Cắt ống", "Bơm thêm bóng"]'::jsonb, 1, 'Phải rút hết nước trong bóng chèn trước khi rút thông để tránh tổn thương niệu đạo.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0600', 'S3.7', 2, 'single_choice', 'Theo dõi sau đặt thông tiểu gồm:', '["Chỉ màu", "Số lượng, màu sắc nước tiểu, độ thông và dấu hiệu nhiễm khuẩn", "Chỉ giờ đặt", "Không cần"]'::jsonb, 1, 'Theo dõi lượng - màu nước tiểu, ống có thông không và dấu hiệu nhiễm khuẩn (sốt, tiểu đục, đau).', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0601', 'S3.7', 1, 'single_choice', 'Cố định thông tiểu ở đùi/bụng nhằm:', '["Thẩm mỹ", "Giảm kéo căng, tổn thương niệu đạo và tuột thông", "Tăng lưu lượng", "Giữ ấm"]'::jsonb, 1, 'Cố định thông giảm lực kéo lên niệu đạo, tránh tổn thương và tuột thông ngoài ý muốn.', '', ARRAY['KT06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0602', 'S3.8', 2, 'single_choice', 'Dấu hiệu chắc chắn ống nội khí quản KHÔNG nằm trong khí quản (vào thực quản):', '["SpO2 tăng", "EtCO2 không có sóng và bụng chướng dần khi bóp bóng", "Phổi nghe rõ hai bên", "NB hồng hào"]'::jsonb, 1, 'Không có sóng EtCO2 kèm chướng bụng khi thông khí là dấu hiệu ống vào thực quản; phải rút và đặt lại.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0603', 'S3.8', 1, 'single_choice', 'Dụng cụ dùng để nhìn thanh môn khi đặt nội khí quản là:', '["Ống nghe", "Đèn soi thanh quản (laryngoscope)", "Máy đo HA", "Nhiệt kế"]'::jsonb, 1, 'Đèn soi thanh quản (trực tiếp hoặc video) giúp bộc lộ thanh môn để đưa ống nội khí quản vào khí quản.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0604', 'S3.8', 2, 'single_choice', 'Khi đặt nội khí quản khó, phương án hỗ trợ thông khí tạm thời có thể dùng:', '["Không làm gì", "Bóng - mặt nạ hoặc mask thanh quản (LMA) để duy trì oxy", "Cho uống nước", "Ép tim"]'::jsonb, 1, 'Đặt NKQ khó: duy trì oxy bằng bóng-mặt nạ hoặc thiết bị trên thanh môn (LMA) trong khi gọi hỗ trợ.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0605', 'S3.8', 3, 'single_choice', 'Thuốc giãn cơ khử cực succinylcholine chống chỉ định tương đối ở NB:', '["Khỏe mạnh", "Tăng kali máu, bỏng rộng giai đoạn muộn, tổn thương thần kinh cơ", "Trẻ em bình thường", "Người trẻ"]'::jsonb, 1, 'Succinylcholine có thể gây tăng kali nguy hiểm ở NB bỏng rộng, chấn thương cơ/thần kinh, tăng kali sẵn có.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0606', 'S3.8', 1, 'single_choice', 'Theo dõi độ mê nhằm tránh:', '["Mê quá nông (thức tỉnh trong mổ) và quá sâu", "Chỉ tiết kiệm thuốc", "Chỉ giảm chi phí", "Không mục đích"]'::jsonb, 0, 'Theo dõi độ mê giúp tránh thức tỉnh trong mổ (awareness) do mê nông và tác dụng phụ do mê quá sâu.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0607', 'S3.8', 2, 'single_choice', 'Chuẩn bị hút (máy hút, ống hút) trước khởi mê nhằm:', '["Trang trí", "Sẵn sàng làm sạch đường thở khi trào ngược/tiết dịch", "Giảm đau", "Tăng oxy"]'::jsonb, 1, 'Máy hút sẵn sàng để xử lý trào ngược, dịch tiết, máu — bảo vệ đường thở trong khởi mê và đặt ống.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0608', 'S3.8', 3, 'single_choice', 'Dấu hiệu sớm của tăng thân nhiệt ác tính trong gây mê thường là:', '["Hạ thân nhiệt", "Tăng nhanh EtCO2, cứng cơ, tim nhanh, sốt cao muộn", "Tiểu nhiều", "Ngủ sâu"]'::jsonb, 1, 'Tăng thân nhiệt ác tính biểu hiện sớm bằng tăng EtCO2 khó giải thích, cứng cơ, nhịp nhanh; sốt cao đến muộn.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0609', 'S3.8', 1, 'single_choice', 'Vai trò của điều dưỡng phụ mê khi khởi mê nhanh (RSI) gồm:', '["Đứng nhìn", "Thực hiện ấn sụn nhẫn và hỗ trợ dụng cụ theo y lệnh bác sĩ gây mê", "Tự cho thuốc", "Rời phòng"]'::jsonb, 1, 'Trong RSI, ĐD phụ mê thực hiện ấn sụn nhẫn (khi được yêu cầu) và chuẩn bị/đưa dụng cụ hỗ trợ đặt ống.', '', ARRAY['KT07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0610', 'S2.5', 2, 'single_choice', 'Yếu tố "A" trong công cụ bàn giao SBAR là:', '["Action", "Assessment (đánh giá tình trạng hiện tại)", "Age", "Allergy"]'::jsonb, 1, 'SBAR: Situation, Background, Assessment (đánh giá/nhận định), Recommendation.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0611', 'S2.5', 1, 'single_choice', 'Bàn giao thuốc nguy cơ cao (high-alert) cần:', '["Bỏ qua", "Nêu rõ và kiểm tra kỹ (ví dụ insulin, thuốc vận mạch, chống đông)", "Nói chung chung", "Không nhắc"]'::jsonb, 1, 'Thuốc nguy cơ cao dễ gây hại nếu sai; bàn giao phải nêu rõ, đối chiếu liều và tình trạng để tránh sự cố.', '', ARRAY['CS05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0612', 'S2.5', 2, 'single_choice', 'Bàn giao NB chuyển khoa/chuyển viện cần kèm:', '["Không giấy tờ", "Tóm tắt bệnh án, thuốc đang dùng, việc cần theo dõi và bàn giao trực tiếp", "Chỉ tên", "Chỉ chẩn đoán"]'::jsonb, 1, 'Chuyển tuyến/khoa cần hồ sơ tóm tắt, danh mục thuốc, chỉ dẫn theo dõi và bàn giao rõ ràng để bảo đảm liên tục.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0613', 'S2.5', 1, 'single_choice', 'Trong bàn giao, thông tin về dị ứng của NB nên được:', '["Bỏ qua nếu nhẹ", "Nêu rõ để phòng ngừa phản ứng khi dùng thuốc", "Ghi mờ", "Nói sau"]'::jsonb, 1, 'Thông tin dị ứng phải được truyền đạt rõ trong bàn giao để tránh dùng thuốc/vật liệu gây phản ứng.', '', ARRAY['CS05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0614', 'S2.5', 3, 'single_choice', 'Bàn giao bị gián đoạn (điện thoại, người gọi) làm tăng nguy cơ:', '["An toàn hơn", "Bỏ sót thông tin, sai sót chăm sóc", "Nhanh hơn", "Không ảnh hưởng"]'::jsonb, 1, 'Gián đoạn khi bàn giao dễ gây mất/bỏ sót thông tin; nên hạn chế ngắt quãng và dùng quy trình chuẩn hóa.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0615', 'S2.5', 2, 'single_choice', '"Đọc lại - xác nhận" (read-back) y lệnh miệng nhằm:', '["Kéo dài thời gian", "Xác nhận nghe đúng để tránh sai sót y lệnh", "Ghi âm", "Hình thức"]'::jsonb, 1, 'Với y lệnh miệng/qua điện thoại, người nhận đọc lại để người ra y lệnh xác nhận, giảm sai sót truyền đạt.', '', ARRAY['CS05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0616', 'S2.5', 1, 'single_choice', 'Bàn giao ca cần diễn ra:', '["Khi rảnh", "Đúng thời điểm giao ca, có mặt cả hai bên nhận và giao", "Qua tin nhắn tùy ý", "Sau khi về"]'::jsonb, 1, 'Bàn giao đúng thời điểm với sự hiện diện hai bên bảo đảm thông tin được truyền và xác nhận đầy đủ.', '', ARRAY['CS05','CS06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0617', 'S2.6', 2, 'single_choice', 'Đường nuôi dưỡng ưu tiên cho NB không ăn được qua miệng nhưng ruột hoạt động:', '["Tĩnh mạch hoàn toàn", "Nuôi ăn qua ống thông (sonde) đường tiêu hóa", "Nhịn", "Chỉ truyền dịch"]'::jsonb, 1, 'Khi ruột còn hoạt động nhưng không ăn được bằng miệng, ưu tiên nuôi ăn qua sonde hơn là tĩnh mạch.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0618', 'S2.6', 1, 'single_choice', 'Kiểm tra vị trí ống thông dạ dày trước khi cho ăn nhằm:', '["Thẩm mỹ", "Tránh bơm thức ăn vào phổi (ống lạc vào đường thở)", "Giảm đau", "Tăng cân"]'::jsonb, 1, 'Xác nhận đúng vị trí ống thông trước mỗi lần cho ăn để tránh bơm dinh dưỡng vào đường hô hấp gây hít sặc.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0619', 'S2.6', 2, 'single_choice', 'Cho ăn qua sonde nên nâng đầu giường vì:', '["Cho đẹp", "Giảm nguy cơ trào ngược và hít sặc", "Tăng hấp thu đường", "Giảm đau"]'::jsonb, 1, 'Nâng đầu giường 30-45 độ khi và sau khi cho ăn qua sonde giúp giảm trào ngược - hít sặc.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0620', 'S2.6', 1, 'single_choice', 'Nhu cầu protein tăng ở NB sau phẫu thuật lớn nhằm:', '["Tăng cân đơn thuần", "Hỗ trợ lành vết thương và phục hồi khối cơ", "Giảm đau", "An thần"]'::jsonb, 1, 'Sau phẫu thuật, nhu cầu protein tăng để hỗ trợ tổng hợp mô, lành vết thương và phục hồi.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0621', 'S2.6', 3, 'single_choice', 'Theo dõi khi bắt đầu nuôi ăn lại ở NB suy kiệt nặng cần chú ý điện giải:', '["Không cần", "Phospho, kali, magie (nguy cơ hội chứng nuôi ăn lại)", "Chỉ natri", "Chỉ calci"]'::jsonb, 1, 'NB suy kiệt khi nuôi ăn lại dễ hạ phospho/kali/magie (refeeding syndrome); cần theo dõi và bù, tăng năng lượng từ từ.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0622', 'S2.6', 2, 'single_choice', 'Dấu hiệu không dung nạp nuôi ăn qua sonde gồm:', '["Không có", "Chướng bụng, nôn, tồn dư dạ dày nhiều, tiêu chảy", "Đói", "Buồn ngủ"]'::jsonb, 1, 'Không dung nạp biểu hiện chướng bụng, nôn, dịch tồn dư dạ dày cao, tiêu chảy; cần điều chỉnh tốc độ/công thức.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0623', 'S2.6', 1, 'single_choice', 'Vệ sinh khi pha và cho ăn qua sonde nhằm:', '["Thẩm mỹ", "Phòng nhiễm khuẩn tiêu hóa cho người bệnh", "Tăng vị", "Giảm đau"]'::jsonb, 1, 'Thao tác sạch khi chuẩn bị và cho ăn qua sonde giảm nguy cơ nhiễm khuẩn đường tiêu hóa.', '', ARRAY['CS08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0624', 'S4.1', 1, 'single_choice', 'Găng tay y tế trong phòng ngừa chuẩn cần được:', '["Dùng lại nhiều NB", "Thay giữa các người bệnh và vệ sinh tay sau khi tháo", "Đeo cả ngày", "Không cần thay"]'::jsonb, 1, 'Găng dùng một lần, thay giữa các NB; đeo găng không thay thế vệ sinh tay — phải rửa tay sau khi tháo găng.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0625', 'S4.1', 2, 'single_choice', 'Sau khi tháo găng, việc bắt buộc tiếp theo là:', '["Đeo găng mới ngay", "Vệ sinh tay", "Đi ra ngoài", "Không làm gì"]'::jsonb, 1, 'Tay vẫn có thể nhiễm bẩn qua lỗ nhỏ hoặc khi tháo găng; phải vệ sinh tay ngay sau khi tháo găng.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0626', 'S4.1', 1, 'single_choice', 'Khẩu trang y tế cần thay khi:', '["Không bao giờ", "Ẩm ướt, bẩn hoặc sau mỗi ca tiếp xúc nguy cơ", "Cuối tuần", "Sau 1 tháng"]'::jsonb, 1, 'Khẩu trang mất hiệu quả khi ẩm/bẩn; cần thay đúng lúc, không sờ mặt ngoài và vệ sinh tay sau khi tháo.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0627', 'S4.1', 2, 'single_choice', 'Phơi nhiễm nghề nghiệp với máu (kim đâm) cần xử trí ngay:', '["Bịt kín", "Rửa vết thương dưới vòi nước, để chảy máu tự nhiên, báo cáo và đánh giá dự phòng", "Nặn mạnh", "Bỏ qua"]'::jsonb, 1, 'Sau kim đâm: rửa ngay dưới nước, không nặn mạnh, báo cáo để đánh giá phơi nhiễm và dự phòng (HIV/HBV) kịp thời.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0628', 'S4.1', 1, 'single_choice', 'Vệ sinh tay bằng nước và xà phòng cần chà tối thiểu khoảng:', '["5 giây", "20-30 giây (đủ 6 bước, phủ mọi bề mặt)", "2 phút", "Không cần thời gian"]'::jsonb, 1, 'Rửa tay đủ khoảng 20-30 giây theo các bước, phủ mọi bề mặt và kẽ tay, sau đó làm khô đúng cách.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0629', 'S4.1', 3, 'single_choice', 'NB nghi lao phổi ho khạc, cần biện pháp phòng lây nào cho nhân viên?', '["Khẩu trang vải", "Khẩu trang N95 và cách ly đường không khí", "Chỉ găng", "Chỉ áo choàng"]'::jsonb, 1, 'Lao lây qua không khí; cần khẩu trang hô hấp N95, buồng áp lực âm và các biện pháp cách ly đường không khí.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0630', 'S4.1', 2, 'single_choice', 'Thu gom đồ vải/ga dính máu dịch cần:', '["Vứt chung rác thường", "Cho vào túi đúng quy định, không giũ mạnh, mang PPE phù hợp", "Giặt tay ngay tại chỗ", "Phơi trong phòng"]'::jsonb, 1, 'Đồ vải nhiễm bẩn thu gom vào bao đúng màu quy định, tránh giũ tung phát tán vi sinh vật, mang PPE khi xử lý.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0631', 'S4.1', 1, 'single_choice', 'Nguyên tắc chung của phòng ngừa chuẩn là coi:', '["Chỉ NB nhiễm mới nguy hiểm", "Mọi máu và dịch cơ thể đều có khả năng lây nhiễm", "Nhân viên miễn nhiễm", "Không cần PPE"]'::jsonb, 1, 'Phòng ngừa chuẩn giả định mọi máu/dịch cơ thể của mọi NB đều có thể lây nhiễm, nên luôn áp dụng biện pháp bảo vệ.', '', ARRAY['VB03'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0632', 'S4.2', 2, 'single_choice', 'Yếu tố nguy cơ nhiễm khuẩn vết mổ liên quan người bệnh gồm:', '["Trẻ khỏe", "Đái tháo đường, béo phì, suy dinh dưỡng, hút thuốc", "Không có", "Uống đủ nước"]'::jsonb, 1, 'Nguy cơ SSI tăng ở NB đái tháo đường, béo phì, suy dinh dưỡng, hút thuốc, suy giảm miễn dịch.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0633', 'S4.2', 1, 'single_choice', 'Kháng sinh dự phòng phẫu thuật thường được ngưng trong vòng:', '["7 ngày", "24 giờ sau mổ (đa số trường hợp)", "1 tháng", "Không ngưng"]'::jsonb, 1, 'Kháng sinh dự phòng thường chỉ dùng ngắn, ngưng trong vòng 24 giờ sau mổ để tránh kháng thuốc, trừ chỉ định riêng.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0634', 'S4.2', 2, 'single_choice', 'Duy trì thân nhiệt bình thường (normothermia) trong mổ giúp:', '["Tăng nhiễm", "Giảm nguy cơ nhiễm khuẩn vết mổ và rối loạn đông máu", "Tăng chảy máu", "Không tác dụng"]'::jsonb, 1, 'Hạ thân nhiệt trong mổ làm co mạch, giảm tưới máu mô và tăng SSI; giữ ấm bình thường có lợi.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0635', 'S4.2', 3, 'single_choice', 'Chất thải sắc nhọn y tế được thu gom vào:', '["Túi vàng thường", "Hộp kháng thủng chuyên dụng", "Túi xanh", "Thùng rác thường"]'::jsonb, 1, 'Vật sắc nhọn bỏ vào hộp kháng thủng riêng để phòng tổn thương và lây nhiễm; không bỏ chung túi mềm.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0636', 'S4.2', 1, 'single_choice', 'Vệ sinh môi trường bề mặt trong bệnh viện nhằm:', '["Thẩm mỹ", "Giảm tải vi sinh vật, cắt đường lây qua bề mặt tiếp xúc", "Tiết kiệm", "Không mục đích"]'::jsonb, 1, 'Làm sạch - khử khuẩn bề mặt thường xuyên giảm mầm bệnh trên môi trường, hạn chế lây truyền qua tiếp xúc.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0637', 'S4.2', 2, 'single_choice', 'Dụng cụ "không thiết yếu" (chỉ tiếp xúc da lành, ví dụ băng đo HA) cần:', '["Tiệt khuẩn", "Làm sạch/khử khuẩn mức thấp là đủ", "Bỏ đi sau 1 lần", "Ngâm cồn 24h"]'::jsonb, 1, 'Theo Spaulding, dụng cụ tiếp xúc da lành (non-critical) chỉ cần làm sạch/khử khuẩn mức thấp.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0638', 'S4.2', 2, 'single_choice', 'Giám sát tuân thủ vệ sinh tay của nhân viên nhằm:', '["Xử phạt", "Đo lường và cải thiện thực hành để giảm nhiễm khuẩn bệnh viện", "Hình thức", "Thống kê suông"]'::jsonb, 1, 'Giám sát tuân thủ vệ sinh tay giúp phản hồi, đào tạo và nâng tỷ lệ tuân thủ — giảm NKBV.', '', ARRAY['VB04'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0639', 'S4.3', 2, 'single_choice', 'Ba giai đoạn của bảng kiểm an toàn phẫu thuật WHO theo thứ tự:', '["Time out - Sign in - Sign out", "Sign in - Time out - Sign out", "Sign out - Time out - Sign in", "Chỉ Time out"]'::jsonb, 1, 'Thứ tự: Sign in (trước khởi mê), Time out (trước rạch da), Sign out (trước khi rời phòng mổ).', '', ARRAY['VB05','VB10'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0640', 'S4.3', 1, 'single_choice', 'Ở bước Sign out, kíp mổ xác nhận:', '["Chỉ tên NB", "Tên thủ thuật đã làm, đếm dụng cụ/gạc đủ, nhãn bệnh phẩm, vấn đề cần lưu ý", "Chi phí", "Ca kế tiếp"]'::jsonb, 1, 'Sign out xác nhận thủ thuật đã thực hiện, số đếm dụng cụ - gạc khớp, dán nhãn bệnh phẩm và dặn dò hậu phẫu.', '', ARRAY['VB05','VB10'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0641', 'S4.3', 2, 'single_choice', 'Mục "kháng sinh dự phòng đã dùng trong 60 phút" được kiểm ở bước:', '["Sign out", "Time out (trước rạch da)", "Sau mổ", "Không có"]'::jsonb, 1, 'Time out kiểm tra kháng sinh dự phòng đã dùng đúng thời điểm cùng xác nhận NB - vị trí - thủ thuật.', '', ARRAY['VB05','VB10'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0642', 'S4.3', 3, 'single_choice', 'Sự cố sót gạc trong cơ thể NB được phân loại là:', '["Biến chứng thường", "Sự cố nghiêm trọng (never event) cần điều tra hệ thống", "Bình thường", "Không cần báo"]'::jsonb, 1, 'Sót dụng cụ/gạc là never event; ngoài xử trí NB, phải báo cáo và phân tích nguyên nhân gốc để phòng tái diễn.', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0643', 'S4.3', 1, 'single_choice', 'Đánh dấu vị trí mổ giúp phòng:', '["Nhiễm khuẩn", "Mổ nhầm vị trí (wrong-site surgery)", "Mất máu", "Đau"]'::jsonb, 1, 'Đánh dấu vị trí trước mổ, có sự tham gia của NB, là biện pháp phòng mổ nhầm vị trí.', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0644', 'S4.3', 2, 'single_choice', 'Báo cáo sự cố suýt xảy ra (near miss) có giá trị vì:', '["Vô ích", "Giúp phát hiện lỗ hổng hệ thống trước khi gây hại thật", "Để phạt", "Không liên quan"]'::jsonb, 1, 'Near miss là cơ hội học hỏi để vá lỗ hổng an toàn trước khi xảy ra tổn hại thực sự cho NB.', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0645', 'S4.3', 1, 'single_choice', 'Mục tiêu chung của các bảng kiểm an toàn là:', '["Thêm giấy tờ", "Chuẩn hóa, nhắc việc và tăng giao tiếp nhóm để giảm sai sót", "Đánh giá nhân viên", "Tính lương"]'::jsonb, 1, 'Checklist chuẩn hóa các bước quan trọng, hỗ trợ trí nhớ và thúc đẩy giao tiếp nhóm, giảm sự cố phòng ngừa được.', '', ARRAY['VB05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0646', 'S4.4', 1, 'single_choice', 'Nguyên tắc "FIFO" trong quản lý kho nghĩa là:', '["Hết hạn trước xuất trước", "Nhập trước xuất trước (First In First Out)", "Xuất ngẫu nhiên", "Giữ hàng mới"]'::jsonb, 1, 'FIFO: hàng nhập trước xuất trước, giúp luân chuyển tồn kho và giảm tồn đọng hàng cũ.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0647', 'S4.4', 2, 'single_choice', 'Với vật tư có hạn dùng, ưu tiên áp dụng nguyên tắc nào?', '["LIFO", "FEFO (hết hạn trước xuất trước)", "Ngẫu nhiên", "Giữ lâu nhất"]'::jsonb, 1, 'FEFO ưu tiên xuất hàng gần hết hạn trước, phù hợp vật tư - thuốc y tế để giảm hao hụt do quá hạn.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0648', 'S4.4', 1, 'single_choice', 'Vật tư y tế vô khuẩn sắp hết hạn nên:', '["Vẫn dùng vô tư", "Ưu tiên dùng trước hoặc loại bỏ khi quá hạn, không dùng hàng hết hạn", "Cất lâu hơn", "Bán lại"]'::jsonb, 1, 'Ưu tiên dùng hàng gần hạn còn hiệu lực; tuyệt đối không dùng vật tư đã quá hạn cho NB.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0649', 'S4.4', 2, 'single_choice', 'Ghi chép xuất - nhập vật tư nhằm:', '["Hình thức", "Kiểm soát tồn kho, truy xuất và lập kế hoạch bổ sung", "Tăng chi phí", "Không mục đích"]'::jsonb, 1, 'Sổ/nhật ký xuất nhập giúp theo dõi tồn kho, truy xuất số lô khi cần và dự trù bổ sung kịp thời.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0650', 'S4.4', 3, 'single_choice', 'Khi nhận cảnh báo thu hồi (recall) một lô vật tư, xử trí:', '["Dùng nốt cho hết", "Ngừng dùng, tách riêng lô bị thu hồi và xử lý theo thông báo", "Bỏ qua", "Chỉ báo miệng"]'::jsonb, 1, 'Nhận recall phải ngừng sử dụng ngay, cách ly lô liên quan và xử lý/hoàn trả theo hướng dẫn của nhà cung cấp/cơ quan.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0651', 'S4.4', 1, 'single_choice', 'Bảo quản vật tư cần theo dõi điều kiện nào của kho?', '["Chỉ ánh sáng", "Nhiệt độ, độ ẩm, vệ sinh và an ninh", "Chỉ diện tích", "Không cần"]'::jsonb, 1, 'Kho vật tư y tế cần kiểm soát nhiệt độ, độ ẩm, vệ sinh và an ninh để bảo đảm chất lượng và tránh mất mát.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0652', 'S4.4', 2, 'single_choice', 'Định mức tồn kho tối thiểu (min stock) giúp:', '["Tồn kho vô hạn", "Cảnh báo bổ sung kịp thời, tránh thiếu vật tư khi cần", "Tăng lãng phí", "Không mục đích"]'::jsonb, 1, 'Đặt ngưỡng tồn tối thiểu để kích hoạt đặt hàng, tránh gián đoạn do hết vật tư trong lúc phẫu thuật/chăm sóc.', '', ARRAY['KT09'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0653', 'S5.1', 2, 'single_choice', 'Trong CPR, khi có 2 người cứu hộ và đã đặt đường thở nâng cao (NKQ), thông khí được thực hiện:', '["Vẫn 30:2", "Ép tim liên tục, thông khí ~1 nhịp mỗi 6 giây không ngắt ép", "Ngừng ép để thổi", "Chỉ ép tim"]'::jsonb, 1, 'Sau khi có đường thở nâng cao, ép tim liên tục và thông khí khoảng 1 nhịp mỗi 6 giây, không dừng ép để thổi.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0654', 'S5.1', 1, 'single_choice', 'Sau mỗi lần ép tim cần:', '["Tì đè liên tục", "Để lồng ngực nảy lại hoàn toàn", "Ép nhanh hơn", "Ép nông"]'::jsonb, 1, 'Để ngực nảy hồi phục hoàn toàn giữa các lần ép giúp tim đổ đầy, tăng hiệu quả tưới máu.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0655', 'S5.1', 2, 'single_choice', 'Nhịp có thể sốc điện (shockable) trong ngừng tim gồm:', '["Vô tâm thu", "Rung thất và nhịp nhanh thất vô mạch", "Hoạt động điện vô mạch", "Nhịp xoang"]'::jsonb, 1, 'Rung thất (VF) và nhịp nhanh thất vô mạch (pVT) là nhịp cần sốc; vô tâm thu và PEA không sốc.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0656', 'S5.1', 1, 'single_choice', 'Khi dùng AED, trong lúc máy phân tích nhịp cần:', '["Tiếp tục ép", "Không chạm vào nạn nhân", "Bế nạn nhân", "Đổ nước"]'::jsonb, 1, 'Khi AED phân tích và khi sốc, mọi người không chạm nạn nhân để tránh nhiễu và bị điện giật.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0657', 'S5.1', 3, 'single_choice', 'Nguyên nhân ngừng tim có thể hồi phục thường được nhớ theo:', '["ABCDE", "5H và 5T (thiếu oxy, giảm thể tích, kali, thân nhiệt, tràn khí...)", "SBAR", "FAST"]'::jsonb, 1, 'Các nguyên nhân hồi phục được (5H/5T): thiếu oxy, giảm thể tích, H+, hạ/tăng kali, hạ thân nhiệt; tràn khí, chèn ép tim, ngộ độc, huyết khối...', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0658', 'S5.1', 2, 'single_choice', 'Chất lượng CPR tốt được đánh giá qua:', '["Ép càng nhanh càng tốt", "Tần số 100-120, sâu 5-6 cm, ngực nảy lại, ít gián đoạn", "Chỉ thổi ngạt", "Ép nông liên tục"]'::jsonb, 1, 'CPR chất lượng: tần số 100-120/phút, độ sâu 5-6 cm, để ngực nảy hoàn toàn, giảm tối đa gián đoạn.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0659', 'S5.1', 1, 'single_choice', 'Ở người lớn bất tỉnh, ngừng thở/thở ngáp và không bắt được mạch trong 10 giây, cần:', '["Chờ thêm", "Bắt đầu ép tim ngay và gọi hỗ trợ/AED", "Cho uống nước", "Vỗ nhẹ"]'::jsonb, 1, 'Không mạch/không thở bình thường trong 10 giây: khởi động CPR ngay và huy động hỗ trợ, lấy AED.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0660', 'S5.1', 2, 'single_choice', 'Vị trí đặt điện cực AED chuẩn cho người lớn là:', '["Cùng một bên", "Dưới xương đòn phải và bên hông trái dưới nách", "Trên bụng", "Trên lưng hai bên"]'::jsonb, 1, 'Điện cực AED đặt dưới đòn phải và vùng nách trái (mỏm tim) để dòng điện đi qua tim hiệu quả.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0661', 'S5.2', 1, 'single_choice', 'Ngay khi nghi phản ứng truyền máu, ưu tiên số 1 là:', '["Báo người nhà", "Ngừng truyền, giữ ven bằng NaCl 0,9%", "Cho ăn", "Tăng tốc độ"]'::jsonb, 1, 'Ngừng truyền ngay và duy trì đường truyền bằng nước muối sinh lý là bước đầu tiên khi nghi phản ứng.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0662', 'S5.2', 3, 'single_choice', 'Trong phản ứng tan máu cấp, để bảo vệ thận cần:', '["Hạn chế dịch", "Duy trì thể tích tuần hoàn/nước tiểu theo y lệnh, theo dõi sát", "Nhịn hoàn toàn", "Cho lợi tiểu bừa"]'::jsonb, 1, 'Duy trì tưới máu và bài niệu (bù dịch, thuốc theo y lệnh) giúp bảo vệ thận khỏi tổn thương do hemoglobin tự do.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0663', 'S5.2', 2, 'single_choice', 'Sau phản ứng truyền máu, mẫu bệnh phẩm và túi máu được gửi lại để:', '["Bỏ đi", "Xét nghiệm đối chiếu, tìm nguyên nhân (nhóm máu, cấy khuẩn...)", "Lưu kỷ niệm", "Trả NB"]'::jsonb, 1, 'Điều tra phản ứng cần gửi túi máu, dây truyền và mẫu NB để kiểm tra lại định nhóm, phản ứng chéo, cấy khuẩn.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0664', 'S5.2', 1, 'single_choice', 'Adrenaline tiêm bắp là điều trị đầu tay của:', '["Sốt nhẹ", "Phản vệ", "Táo bón", "Đau đầu"]'::jsonb, 1, 'Phản vệ (kể cả do truyền máu/thuốc) cần adrenaline tiêm bắp ngay lập tức là điều trị đầu tay.', '', ARRAY['KT02','CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0665', 'S5.2', 2, 'single_choice', 'Dị ứng nhẹ (mày đay) khi truyền máu thường xử trí:', '["Ngừng vĩnh viễn mọi truyền", "Tạm ngừng, dùng kháng histamin theo y lệnh, theo dõi", "Tăng tốc độ", "Bỏ qua"]'::jsonb, 1, 'Dị ứng nhẹ: tạm ngừng, dùng kháng histamin theo y lệnh; nếu ổn có thể truyền lại chậm dưới theo dõi.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0666', 'S5.2', 3, 'single_choice', 'TRALI (tổn thương phổi cấp liên quan truyền máu) biểu hiện:', '["Táo bón", "Khó thở, giảm oxy máu, phù phổi không do tim trong vài giờ", "Sốt nhẹ đơn thuần", "Ngứa"]'::jsonb, 1, 'TRALI gây suy hô hấp cấp, phù phổi không do quá tải, thường trong 6 giờ sau truyền; cần hỗ trợ hô hấp và ngừng truyền.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0667', 'S5.2', 1, 'single_choice', 'Biện pháp phòng ngừa quan trọng nhất với tai biến truyền máu là:', '["Truyền nhanh", "Đối chiếu định danh NB - đơn vị máu và theo dõi sát", "Hâm nóng máu", "Truyền nhiều đơn vị"]'::jsonb, 1, 'Phần lớn tai biến nặng do sai định danh; đối chiếu chặt chẽ và theo dõi sát là phòng ngừa then chốt.', '', ARRAY['KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0668', 'S5.3', 3, 'single_choice', 'NB hồi tỉnh thở chậm, đồng tử co nhỏ, lơ mơ sau opioid liều cao. Thuốc đối kháng:', '["Flumazenil", "Naloxone", "Atropine", "Adrenaline"]'::jsonb, 1, 'Naloxone là thuốc đối kháng opioid, dùng khi ức chế hô hấp do opioid; hỗ trợ hô hấp song song.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0669', 'S5.3', 2, 'single_choice', 'NB sau mổ run lạnh dữ dội kèm SpO2 giảm nhẹ, xử trí:', '["Chườm lạnh", "Ủ ấm, cho oxy và dùng thuốc theo y lệnh", "Cho vận động mạnh", "Bỏ qua"]'::jsonb, 1, 'Run làm tăng tiêu thụ oxy; ủ ấm, bổ sung oxy và thuốc (theo y lệnh) giúp kiểm soát và ổn định SpO2.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0670', 'S5.3', 3, 'single_choice', 'NB hồi tỉnh đột ngột co giật toàn thân — ưu tiên xử trí đầu tiên:', '["Ghi hồ sơ", "Bảo vệ đường thở, tránh chấn thương, cho oxy và gọi hỗ trợ", "Cho ăn", "Giữ chặt tay chân"]'::jsonb, 1, 'Cơn co giật: bảo đảm an toàn (tránh chấn thương), khai thông/hỗ trợ đường thở, cho oxy, gọi hỗ trợ và dùng thuốc theo y lệnh.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0671', 'S5.3', 2, 'single_choice', 'Buồn nôn - nôn dữ dội sau mổ nguy hiểm nhất khi:', '["NB tỉnh táo", "NB còn lơ mơ, phản xạ bảo vệ đường thở kém (nguy cơ hít sặc)", "NB đói", "NB đau"]'::jsonb, 1, 'Nôn ở NB tri giác giảm dễ gây hít sặc; cần tư thế an toàn, hút sẵn sàng và chống nôn theo y lệnh.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0672', 'S5.3', 1, 'single_choice', 'Khi phát hiện NB tím tái, ngừng thở tại hồi tỉnh, hành động đầu tiên:', '["Đo huyết áp", "Gọi hỗ trợ và khai thông đường thở, thông khí/oxy ngay", "Ghi chép", "Cho thuốc uống"]'::jsonb, 1, 'Ngừng thở/tím tái cần huy động hỗ trợ và can thiệp đường thở - thông khí ngay lập tức theo trình tự cấp cứu.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0673', 'S5.3', 2, 'single_choice', 'NB gây tê tủy sống tụt huyết áp, mạch chậm — xử trí gồm:', '["Cho ngồi dậy", "Bù dịch, thuốc co mạch và atropine theo y lệnh, nằm đầu thấp", "Hạn chế dịch", "Chỉ theo dõi"]'::jsonb, 1, 'Tê tủy sống gây giãn mạch và có thể chậm nhịp; xử trí bằng bù dịch, thuốc co mạch, atropine (nếu chậm nhịp) theo y lệnh.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0674', 'S5.3', 3, 'single_choice', 'Dấu hiệu gợi ý phản vệ trong/ sau gây mê gồm:', '["Chỉ buồn ngủ", "Tụt HA nặng, co thắt phế quản, mày đay/phù, mạch nhanh khởi phát nhanh", "Táo bón", "Tăng HA đơn thuần"]'::jsonb, 1, 'Phản vệ chu phẫu biểu hiện tụt HA, khó thở/co thắt phế quản, ban đỏ - phù, khởi phát nhanh; xử trí adrenaline, dịch, oxy.', '', ARRAY['CS07','KT02'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0675', 'S5.3', 1, 'single_choice', 'Nguyên tắc theo dõi NB hồi tỉnh để phát hiện sớm biến cố là:', '["Kiểm tra 1 lần", "Theo dõi liên tục dấu hiệu sinh tồn, SpO2, tri giác theo tần suất quy định", "Chỉ khi NB kêu", "Không cần"]'::jsonb, 1, 'Phát hiện sớm biến cố hồi tỉnh dựa trên theo dõi liên tục/định kỳ sinh tồn, SpO2, tri giác, hô hấp và đau.', '', ARRAY['CS07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0676', 'S6.1', 1, 'single_choice', 'Chăm sóc điều dưỡng lấy trung tâm là:', '["Bệnh viện", "Người bệnh (patient-centered)", "Bác sĩ", "Thiết bị"]'::jsonb, 1, 'Chăm sóc lấy người bệnh làm trung tâm: tôn trọng nhu cầu, giá trị và sự tham gia của NB vào quyết định.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0677', 'S6.1', 2, 'single_choice', 'Phân cấp chăm sóc cấp I (chăm sóc toàn diện) dành cho:', '["NB tự phục vụ", "NB nặng, phụ thuộc hoàn toàn vào điều dưỡng", "NB ngoại trú", "NB khỏe"]'::jsonb, 1, 'Chăm sóc cấp I dành cho NB nặng/nguy kịch, cần theo dõi và hỗ trợ toàn diện, liên tục của điều dưỡng.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0678', 'S6.1', 1, 'single_choice', 'Quy trình điều dưỡng gồm các bước theo trình tự:', '["Chỉ thực hiện", "Nhận định - chẩn đoán ĐD - lập kế hoạch - thực hiện - lượng giá", "Chỉ ghi chép", "Chỉ đánh giá"]'::jsonb, 1, 'Quy trình điều dưỡng: nhận định, chẩn đoán điều dưỡng, lập kế hoạch, thực hiện và lượng giá.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0679', 'S6.1', 2, 'single_choice', 'Đánh giá và ghi nhận dấu hiệu sinh tồn là nhiệm vụ:', '["Chỉ bác sĩ", "Cơ bản của điều dưỡng trong theo dõi người bệnh", "Không cần làm", "Của hộ lý"]'::jsonb, 1, 'Theo dõi, ghi nhận và báo cáo dấu hiệu sinh tồn là nhiệm vụ nền tảng của điều dưỡng trong chăm sóc.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0680', 'S6.1', 3, 'single_choice', 'Điều dưỡng phát hiện dấu hiệu xấu đi của NB (ví dụ theo thang cảnh báo sớm) cần:', '["Chờ khám định kỳ", "Báo cáo/kích hoạt hỗ trợ kịp thời theo quy trình", "Tự xử trí ngoài phạm vi", "Ghi rồi để đó"]'::jsonb, 1, 'Hệ thống cảnh báo sớm (EWS) yêu cầu ĐD báo cáo và kích hoạt hỗ trợ khi NB xấu đi để can thiệp kịp thời.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0681', 'S6.1', 1, 'single_choice', 'Giáo dục sức khỏe cho người bệnh và thân nhân là:', '["Không thuộc ĐD", "Một chức năng của điều dưỡng nhằm nâng cao tự chăm sóc", "Chỉ khi rảnh", "Của phòng hành chính"]'::jsonb, 1, 'Tư vấn - giáo dục sức khỏe là chức năng của điều dưỡng, giúp NB và gia đình tự chăm sóc và tuân thủ điều trị.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0682', 'S6.1', 2, 'single_choice', 'Bảo đảm chất lượng chăm sóc điều dưỡng dựa vào:', '["Cảm tính", "Tiêu chuẩn, quy trình, giám sát và cải tiến liên tục", "Kinh nghiệm cá nhân đơn thuần", "May rủi"]'::jsonb, 1, 'Chất lượng chăm sóc dựa trên chuẩn/quy trình, đo lường - giám sát và cải tiến liên tục dựa trên bằng chứng.', '', ARRAY['VB07'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0683', 'S6.1', 1, 'single_choice', 'Người bệnh có quyền được:', '["Giấu thông tin bệnh", "Tôn trọng, được thông tin và tham gia quyết định chăm sóc", "Bị ép điều trị", "Không được giải thích"]'::jsonb, 1, 'NB có quyền được tôn trọng, được cung cấp thông tin và tham gia vào quyết định về chăm sóc/điều trị.', '', ARRAY['VB07','VB06'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0684', 'S6.2', 2, 'single_choice', 'Phân loại ASA III mô tả người bệnh:', '["Khỏe mạnh", "Có bệnh toàn thân nặng nhưng chưa mất chức năng đe dọa tính mạng", "Sắp tử vong", "Đã chết não"]'::jsonb, 1, 'ASA III: NB có bệnh toàn thân nặng, giới hạn chức năng nhưng chưa ở mức đe dọa tính mạng thường xuyên.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0685', 'S6.2', 1, 'single_choice', 'Khám tiền mê nên được thực hiện:', '["Ngay khi khởi mê", "Trước ngày/trước cuộc mổ để đánh giá và chuẩn bị", "Sau mổ", "Không cần"]'::jsonb, 1, 'Khám tiền mê thực hiện trước cuộc mổ để phân loại nguy cơ, tối ưu NB và lập kế hoạch gây mê.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0686', 'S6.2', 2, 'single_choice', 'Thông tin quan trọng cần khai thác khi khám tiền mê gồm:', '["Chỉ cân nặng", "Tiền sử bệnh, dị ứng, thuốc đang dùng, tiền sử gây mê và đường thở", "Chỉ nghề nghiệp", "Chỉ địa chỉ"]'::jsonb, 1, 'Tiền mê khai thác bệnh nền, dị ứng, thuốc, tiền sử gây mê/biến chứng và đánh giá đường thở để lập kế hoạch an toàn.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0687', 'S6.2', 1, 'single_choice', 'Theo dõi tối thiểu bắt buộc trong gây mê gồm:', '["Chỉ mạch", "SpO2, EtCO2 (khi mê nội khí quản), điện tim, huyết áp", "Chỉ nhiệt độ", "Chỉ nước tiểu"]'::jsonb, 1, 'Chuẩn theo dõi gây mê tối thiểu: oxy hóa (SpO2), thông khí (EtCO2), tuần hoàn (ECG, HA) và nhiệt độ khi cần.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0688', 'S6.2', 2, 'single_choice', 'Bàn giao NB sau mổ cho hồi tỉnh cần nêu:', '["Chỉ tên", "Loại phẫu thuật/gây mê, thuốc, dịch - máu, biến cố và kế hoạch theo dõi", "Chỉ giờ", "Chỉ chẩn đoán"]'::jsonb, 1, 'Bàn giao cho PACU gồm tóm tắt gây mê - phẫu thuật, thuốc đã dùng, dịch/máu, biến cố và các điểm cần theo dõi.', '', ARRAY['VB08','CS05'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0689', 'S6.2', 3, 'single_choice', 'Quản lý và ghi sổ thuốc gây nghiện trong khoa GMHS yêu cầu:', '["Ghi khi rảnh", "Đối chiếu, ghi sổ chặt chẽ, bàn giao lượng tồn giữa các ca", "Không cần sổ", "Ai giữ cũng được"]'::jsonb, 1, 'Thuốc gây nghiện phải quản lý theo quy chế: ghi sổ, đối chiếu số lượng và bàn giao tồn giữa các ca trực.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0690', 'S6.2', 1, 'single_choice', 'Kiểm tra máy gây mê trước ca là trách nhiệm nhằm:', '["Hình thức", "Phát hiện lỗi thiết bị (rò, van, vôi soda, nguồn khí) trước gây mê", "Tiết kiệm", "Không mục đích"]'::jsonb, 1, 'Machine check trước mỗi ca phát hiện rò rỉ/hỏng hóc và bảo đảm nguồn oxy, van, hấp thu CO2 hoạt động tốt.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0691', 'S6.2', 2, 'single_choice', 'ASA "E" thêm vào phân loại (ví dụ ASA IIE) chỉ:', '["Bệnh nhẹ", "Phẫu thuật cấp cứu (Emergency)", "Trẻ em", "Người già"]'::jsonb, 1, 'Hậu tố E biểu thị phẫu thuật cấp cứu, thường kèm nguy cơ cao hơn so với mổ chương trình cùng nhóm ASA.', '', ARRAY['VB08'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0692', 'S6.3', 1, 'single_choice', 'Bảng kiểm kỹ năng nên được xây dựng dựa trên:', '["Ý kiến cá nhân", "Quy trình chuẩn và bằng chứng, chia thành các bước rõ ràng", "Cảm hứng", "Truyền miệng"]'::jsonb, 1, 'Bảng kiểm dựa trên quy trình chuẩn/bằng chứng, chia thành các bước quan sát được để đánh giá khách quan.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0693', 'S6.3', 2, 'single_choice', 'Đánh giá thực hành bằng OSCE có đặc điểm:', '["Chỉ lý thuyết", "Đánh giá kỹ năng qua các trạm tình huống chuẩn hóa", "Không cần quan sát", "Ngẫu nhiên"]'::jsonb, 1, 'OSCE đánh giá năng lực thực hành qua nhiều trạm với tình huống và tiêu chí chuẩn hóa, tăng khách quan.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0694', 'S6.3', 1, 'single_choice', 'Thang điểm bảng kiểm thường dùng để đánh giá mức đạt là:', '["Chỉ đạt/không đạt duy nhất", "Có/không hoặc thang mức độ (chưa đạt - đạt - thành thạo)", "Xếp hạng ngẫu nhiên", "Không chấm"]'::jsonb, 1, 'Bảng kiểm có thể dùng thang có/không hoặc thang mức độ để phản ánh mức thành thạo từng bước.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0695', 'S6.3', 2, 'single_choice', 'Phản hồi hiệu quả sau đánh giá nên theo mô hình:', '["Chỉ chê", "Ghi nhận điểm mạnh - nêu điểm cần cải thiện - hướng hành động cụ thể", "Chỉ khen", "Không phản hồi"]'::jsonb, 1, 'Phản hồi xây dựng nêu điểm mạnh, chỉ ra điểm cần cải thiện và đề xuất hành động cụ thể để tiến bộ.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0696', 'S6.3', 3, 'single_choice', 'Độ tin cậy giữa các đánh giá viên (inter-rater reliability) được cải thiện nhờ:', '["Chấm tùy hứng", "Tiêu chí rõ ràng và tập huấn thống nhất người đánh giá", "Không có tiêu chí", "Chấm một mình"]'::jsonb, 1, 'Tiêu chí cụ thể và đào tạo người chấm giúp các đánh giá viên cho kết quả nhất quán (tăng inter-rater reliability).', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0697', 'S6.3', 1, 'single_choice', 'Mục đích chính của lượng giá năng lực định kỳ là:', '["Xử phạt", "Bảo đảm và duy trì năng lực thực hành an toàn", "Giảm lương", "Hình thức"]'::jsonb, 1, 'Lượng giá định kỳ nhằm bảo đảm nhân viên duy trì năng lực để thực hành an toàn, không nhằm trừng phạt.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0698', 'S6.3', 2, 'single_choice', 'Chỉ số chất lượng (KPI) chăm sóc điều dưỡng ví dụ như:', '["Màu đồng phục", "Tỷ lệ loét tì đè, té ngã, nhiễm khuẩn liên quan chăm sóc", "Số ghế", "Diện tích phòng"]'::jsonb, 1, 'KPI điều dưỡng gồm tỷ lệ loét tì đè, té ngã, nhiễm khuẩn liên quan chăm sóc (CAUTI, CLABSI) — phản ánh chất lượng.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0699', 'S6.3', 1, 'single_choice', 'Chu trình PDCA áp dụng cải tiến quy trình nghĩa là:', '["Chỉ lập kế hoạch", "Lập kế hoạch - Thực hiện - Kiểm tra - Hành động (điều chỉnh)", "Chỉ thực hiện", "Chỉ kiểm tra"]'::jsonb, 1, 'PDCA là chu trình cải tiến liên tục: Plan - Do - Check - Act, lặp lại để nâng chất lượng.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, skill_id, difficulty, type, question, options, correct_index, explanation, tt32_tag, source_doc_ids, status) VALUES ('Q0700', 'S6.3', 2, 'single_choice', 'Sử dụng bảng kiểm khi thực hiện thủ thuật (ví dụ đặt catheter) giúp:', '["Chậm hơn vô ích", "Giảm bỏ sót bước vô khuẩn/an toàn, giảm biến chứng", "Tăng nhiễm khuẩn", "Không tác dụng"]'::jsonb, 1, 'Áp dụng bảng kiểm khi làm thủ thuật (như đặt catheter tĩnh mạch trung tâm) giảm bỏ sót bước và biến chứng.', '', ARRAY['BK01'], 'approved') ON CONFLICT (id) DO NOTHING;
